
create or replace function public.random_phone_number(mobile boolean, landline boolean)
returns string
language python
runtime_version = '3.8'
handler = 'run'
packages = ('numpy')
as
$$
import numpy
def run(mobile=True, landline=True):
    mobile_patterns = [
        '050-ddd-dddd',
        '052-ddd-dddd',
        '053-ddd-dddd',
        '054-ddd-dddd',
        '058-ddd-dddd',
        '055-55d-dddd',
        '055-6dd-dddd',
        '050-ddddddd',
        '052-ddddddd',
        '053-ddddddd',
        '054-ddddddd'
    ]
    landline_patterns = [
        '02-ddd-dddd',
        '03-ddd-dddd',
        '04-ddd-dddd',
        '08-ddd-dddd',
        '09-ddd-dddd',
        '02-ddddddd',
        '03-ddddddd',
        '04-ddddddd',
        '08-ddddddd',
        '09-ddddddd'
    ]

    phone = numpy.random.choice((mobile_patterns if mobile else []) +
                                (landline_patterns if landline else []))
    return ''.join([str(numpy.random.randint(1, 9))
                    if item == 'd' else item for item in phone])
$$;


create or replace function public.random_ip(IPv4 boolean, IPv6 boolean)
returns string
language python
runtime_version = '3.8'
handler = 'run'
packages = ('numpy')
as
$$
import numpy
def run(IPv4=True, IPv6=True):
    ver = numpy.random.choice((['v4'] if IPv4 else []) + (['v6'] if IPv6 else []))

    if ver == 'v4':
        return '.'.join([str(numpy.random.randint(0, 255)) for _ in range(4)])
    else:
        return ':'.join([str(hex(numpy.random.randint(0, 65535))).lstrip('0x')
                         for _ in range(8)])
$$;


create or replace function public.random_israeli_id()
returns string
language python
runtime_version = '3.8'
handler = 'run'
packages = ('numpy')
as
$$
import numpy
def run():
    id = numpy.random.randint(1_000_000, 99_999_999)
    if id < 10_000_000:
        id = '0' + str(id)
    else:
        id = str(id)

    # calculate check digit
    weights = [1, 2, 1, 2, 1, 2, 1, 2]
    check_digit = [int(num) * weight for num, weight in zip(id, weights)]
    weights_sum = sum([sum(int(digit) for digit in str(item))
                       for item in check_digit])
    check_digit = str(10 - (weights_sum % 10))[-1]
    return id + check_digit
$$;


create or replace function public.random_house_number()
returns string
language python
runtime_version = '3.8'
handler = 'run'
packages = ('numpy')
as
$$
import numpy
def run():
    patterns = [
        'd',
        'd/א',
        'dd',
        'dd כניסה א',
        'dd כניסה ב',
        'dd/א',
        'dd/ב'
    ]

    pattern = numpy.random.choice(patterns)
    return ''.join([item.replace('d', str(numpy.random.randint(1, 9)))
                    for item in pattern])
$$;


